package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class DefaultDateTypeAdapterTest {

  private DefaultDateTypeAdapter<?> adapter;
  private List<DateFormat> dateFormats;

  @BeforeEach
  public void setUp() throws Exception {
    // Use reflection to get the private constructor DefaultDateTypeAdapter(DateType<T> dateType, String datePattern)
    Constructor<DefaultDateTypeAdapter> constructor = DefaultDateTypeAdapter.class.getDeclaredConstructor(
        Class.forName("com.google.gson.internal.bind.DateType"), String.class);
    constructor.setAccessible(true);

    // Create a dummy DateType instance (can be null as it is unused in toString)
    Object dateTypeDummy = null;

    // Instantiate adapter with a date pattern so that dateFormats list is populated
    adapter = constructor.newInstance(dateTypeDummy, "yyyy-MM-dd");

    // Access the private dateFormats field and clear it, then add our own DateFormats for testing
    Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);
    dateFormats.clear();
  }

  @Test
  public void testToString_withSimpleDateFormat() throws Exception {
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
    dateFormats.add(sdf);

    Method toStringMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("toString");
    toStringMethod.setAccessible(true);
    String result = (String) toStringMethod.invoke(adapter);

    assertEquals("DefaultDateTypeAdapter(yyyy-MM-dd)", result);
  }

  @Test
  public void testToString_withNonSimpleDateFormat() throws Exception {
    // Create an anonymous subclass of DateFormat to simulate non-SimpleDateFormat
    DateFormat customFormat = new DateFormat() {
      @Override
      public StringBuffer format(java.util.Date date, StringBuffer toAppendTo, java.text.FieldPosition fieldPosition) {
        return null;
      }
      @Override
      public java.util.Date parse(String source, ParsePosition pos) {
        return null;
      }
      @Override
      public String getClass().getSimpleName() {
        return "CustomDateFormat";
      }
    };
    // But getClass().getSimpleName() is final, so we rely on actual class name
    // So we just add a new DateFormat instance with a custom class name by creating a named class

    class CustomDateFormat extends DateFormat {
      @Override
      public StringBuffer format(java.util.Date date, StringBuffer toAppendTo, java.text.FieldPosition fieldPosition) {
        return null;
      }
      @Override
      public java.util.Date parse(String source, ParsePosition pos) {
        return null;
      }
    }
    DateFormat customDateFormat = new CustomDateFormat();
    dateFormats.add(customDateFormat);

    Method toStringMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("toString");
    toStringMethod.setAccessible(true);
    String result = (String) toStringMethod.invoke(adapter);

    assertEquals("DefaultDateTypeAdapter(CustomDateFormat)", result);
  }
}
